### 5. ScreenRenderer Integration

#### **src/services/sdui/renderer/ScreenRenderer.tsx** (relevant excerpts)

```typescript
// Lines 68-103: renderComponent function
function renderComponent(
  component: SDUIComponent,
  context: SDUIContext,
  registry: SDUIComponentRegistry,
  key: string,
  onAction?: (descriptor: SDUIActionDescriptor) => void,
) {
  // ... visibility and interpolation logic ...

  return (
    <Renderer
      key={key}
      props={interpolatedProps}
      context={context}
      onAction={onAction}
    />
  );
}

// Lines 141-160: onAction callback creation
const onAction = useCallback(
  (descriptor: SDUIActionDescriptor) => {
    if (!actionRegistry) return;

    const signal = abortControllerRef.current.signal;
    const deps: SDUIActionDeps = {
      ...actionDepsRef.current,
      signal,
    };

    executeAction(actionRegistry, descriptor, actionContext, deps).catch(
      (err) => {
        if (typeof __DEV__ !== 'undefined' && __DEV__) {
          console.error('[SDUI] Unhandled action error:', err);
        }
      },
    );
  },
  [actionRegistry, actionContext],
);

const actionHandler = actionRegistry ? onAction : undefined;

// Lines 164-183: Rendering with actionHandler
return (
  <View style={rootStyle}>
    {header &&
      renderComponent(header, mergedContext, activeRegistry, 'header', actionHandler)}

    <View style={rootStyle}>
      {(body ?? []).map((component, index) =>
        renderComponent(
          component,
          mergedContext,
          activeRegistry,
          `${component.type}-${index}`,
          actionHandler,
        ),
      )}
    </View>

    {footer &&
      renderComponent(footer, mergedContext, activeRegistry, 'footer', actionHandler)}
  </View>
);
```

**Key observations:**
- `ScreenRenderer` creates `onAction` callback and passes it to all components
- `onAction` is only defined when `actionRegistry` is provided
- The callback executes actions via `executeAction` from action registry
- AbortController signal is injected at execution time

