  1→import React, { useState, useMemo, useCallback, useEffect, useRef } from 'react';
  2→import { View } from 'react-native';
  3→import type {
  4→  SDUIScreen,
  5→  SDUIComponent,
  6→  SDUIComponentRegistry,
  7→  SDUIComponentProps,
  8→  SDUIContext,
  9→  SDUIConditional,
 10→  SDUIActionDescriptor,
 11→  SDUIActionRegistry,
 12→  SDUIActionDeps,
 13→  SDUIActionContext,
 14→} from '../models';
 15→import { interpolateDeep } from '../utils/interpolation';
 16→import { evaluateRule } from '../utils/jsonLogic';
 17→import { getDefaultRegistry, getRenderer } from '../registry';
 18→import { executeAction } from '../actions/registry';
 19→import FallbackComponent from './FallbackComponent';
 20→
 21→declare const __DEV__: boolean;
 22→
 23→const rootStyle = { flex: 1 } as const;
 24→
 25→interface ScreenRendererProps {
 26→  screen: SDUIScreen;
 27→  registry?: SDUIComponentRegistry;
 28→  actionRegistry?: SDUIActionRegistry;
 29→  actionDeps?: Omit<SDUIActionDeps, 'signal'>;
 30→}
 31→
 32→function isConditional(value: unknown): value is SDUIConditional {
 33→  return (
 34→    value !== null &&
 35→    typeof value === 'object' &&
 36→    'rule' in (value as Record<string, unknown>) &&
 37→    typeof (value as Record<string, unknown>).rule === 'object'
 38→  );
 39→}
 40→
 41→function isVisible(component: SDUIComponent, context: SDUIContext): boolean {
 42→  if (!component.visible) return true;
 43→  const { rule } = component.visible;
 44→  if (!rule || typeof rule !== 'object' || Object.keys(rule).length === 0) {
 45→    return true;
 46→  }
 47→  return evaluateRule(rule, context);
 48→}
 49→
 50→function separateConditionals(props: SDUIComponentProps): {
 51→  interpolatable: SDUIComponentProps;
 52→  conditionals: Record<string, SDUIConditional>;
 53→} {
 54→  const interpolatable: SDUIComponentProps = {};
 55→  const conditionals: Record<string, SDUIConditional> = {};
 56→
 57→  for (const key of Object.keys(props)) {
 58→    if (isConditional(props[key])) {
 59→      conditionals[key] = props[key] as SDUIConditional;
 60→    } else {
 61→      interpolatable[key] = props[key];
 62→    }
 63→  }
 64→
 65→  return { interpolatable, conditionals };
 66→}
 67→
 68→function renderComponent(
 69→  component: SDUIComponent,
 70→  context: SDUIContext,
 71→  registry: SDUIComponentRegistry,
 72→  key: string,
 73→  onAction?: (descriptor: SDUIActionDescriptor) => void,
 74→) {
 75→  if (!isVisible(component, context)) return null;
 76→
 77→  const { interpolatable, conditionals } = separateConditionals(component.props);
 78→  const interpolatedProps = {
 79→    ...interpolateDeep(interpolatable, context),
 80→    ...conditionals,
 81→  };
 82→
 83→  const Renderer = getRenderer(registry, component.type);
 84→
 85→  if (!Renderer) {
 86→    return (
 87→      <FallbackComponent
 88→        key={key}
 89→        type={component.type}
 90→        props={interpolatedProps}
 91→      />
 92→    );
 93→  }
 94→
 95→  return (
 96→    <Renderer
 97→      key={key}
 98→      props={interpolatedProps}
 99→      context={context}
100→      onAction={onAction}
101→    />
102→  );
103→}
104→
105→export default function ScreenRenderer({
106→  screen,
107→  registry,
108→  actionRegistry,
109→  actionDeps,
110→}: ScreenRendererProps) {
111→  const activeRegistry = registry ?? getDefaultRegistry();
112→  const { context, header, body, footer } = screen;
113→
114→  const [formState, setForm] = useState<Record<string, unknown>>({});
115→
116→  const abortControllerRef = useRef(new AbortController());
117→
118→  useEffect(() => {
119→    return () => {
120→      abortControllerRef.current.abort();
121→    };
122→  }, []);
123→
124→  const mergedContext = useMemo<SDUIContext>(
125→    () => ({ ...context, form: formState as unknown as SDUIContext }),
126→    [context, formState],
127→  );
128→
129→  const actionContext = useMemo<SDUIActionContext>(
130→    () => ({
131→      screen: context,
132→      form: formState,
133→      setForm,
134→    }),
135→    [context, formState],
136→  );
137→
138→  const actionDepsRef = useRef(actionDeps);
139→  actionDepsRef.current = actionDeps;
140→
141→  const onAction = useCallback(
142→    (descriptor: SDUIActionDescriptor) => {
143→      if (!actionRegistry) return;
144→
145→      const signal = abortControllerRef.current.signal;
146→      const deps: SDUIActionDeps = {
147→        ...actionDepsRef.current,
148→        signal,
149→      };
150→
151→      executeAction(actionRegistry, descriptor, actionContext, deps).catch(
152→        (err) => {
153→          if (typeof __DEV__ !== 'undefined' && __DEV__) {
154→            console.error('[SDUI] Unhandled action error:', err);
155→          }
156→        },
157→      );
158→    },
159→    [actionRegistry, actionContext],
160→  );
161→
162→  const actionHandler = actionRegistry ? onAction : undefined;
163→
164→  return (
165→    <View style={rootStyle}>
166→      {header &&
167→        renderComponent(header, mergedContext, activeRegistry, 'header', actionHandler)}
168→
169→      <View style={rootStyle}>
170→        {(body ?? []).map((component, index) =>
171→          renderComponent(
172→            component,
173→            mergedContext,
174→            activeRegistry,
175→            `${component.type}-${index}`,
176→            actionHandler,
177→          ),
178→        )}
179→      </View>
180→
181→      {footer &&
182→        renderComponent(footer, mergedContext, activeRegistry, 'footer', actionHandler)}
183→    </View>
184→  );
185→}
