import { View } from 'react-native';
import type {
  SDUIScreen,
  SDUIComponent,
  SDUIComponentRegistry,
  SDUIComponentProps,
  SDUIContext,
  SDUIConditional,
  SDUIActionDescriptor,
  SDUIActionRegistry,
  SDUIActionDeps,
  SDUIActionContext,
} from '../models';
import { interpolateDeep } from '../utils/interpolation';
import { evaluateRule } from '../utils/jsonLogic';
import { getDefaultRegistry, getRenderer } from '../registry';
import { executeAction } from '../actions/registry';
import FallbackComponent from './FallbackComponent';

declare const __DEV__: boolean;

const rootStyle = { flex: 1 } as const;

interface ScreenRendererProps {
  screen: SDUIScreen;
  registry?: SDUIComponentRegistry;
  actionRegistry?: SDUIActionRegistry;
  actionDeps?: Omit<SDUIActionDeps, 'signal'>;
}

function isConditional(value: unknown): value is SDUIConditional {
  return (
    value !== null &&
    typeof value === 'object' &&
    'rule' in (value as Record<string, unknown>) &&
    typeof (value as Record<string, unknown>).rule === 'object'
  );
}

function isVisible(component: SDUIComponent, context: SDUIContext): boolean {
  if (!component.visible) return true;
  const { rule } = component.visible;
  if (!rule || typeof rule !== 'object' || Object.keys(rule).length === 0) {
    return true;
  }
  return evaluateRule(rule, context);
}

function separateConditionals(props: SDUIComponentProps): {
  interpolatable: SDUIComponentProps;
  conditionals: Record<string, SDUIConditional>;
} {
  const interpolatable: SDUIComponentProps = {};
  const conditionals: Record<string, SDUIConditional> = {};

  for (const key of Object.keys(props)) {
    if (isConditional(props[key])) {
      conditionals[key] = props[key] as SDUIConditional;
    } else {
      interpolatable[key] = props[key];
    }
  }

  return { interpolatable, conditionals };
}

function renderComponent(
  component: SDUIComponent,
  context: SDUIContext,
  registry: SDUIComponentRegistry,
  key: string,
  onAction?: (descriptor: SDUIActionDescriptor) => void,
) {
  if (!isVisible(component, context)) return null;

  const { interpolatable, conditionals } = separateConditionals(component.props);
  const interpolatedProps = {
    ...interpolateDeep(interpolatable, context),
    ...conditionals,
  };

  const Renderer = getRenderer(registry, component.type);

  if (!Renderer) {
    return (
      <FallbackComponent
        key={key}
        type={component.type}
        props={interpolatedProps}
      />
    );
  }

  return (
    <Renderer
      key={key}
      props={interpolatedProps}
      context={context}
      onAction={onAction}
    />
  );
}

export default function ScreenRenderer({
  screen,
  registry,
  actionRegistry,
  actionDeps,
}: ScreenRendererProps) {
  const activeRegistry = registry ?? getDefaultRegistry();
  const { context, header, body, footer } = screen;

  const [formState, setForm] = useState<Record<string, unknown>>({});

  const abortControllerRef = useRef(new AbortController());

  useEffect(() => {
    return () => {
      abortControllerRef.current.abort();
    };
  }, []);

  const mergedContext = useMemo<SDUIContext>(
    () => ({ ...context, form: formState as unknown as SDUIContext }),
    [context, formState],
  );

  const actionContext = useMemo<SDUIActionContext>(
    () => ({
      screen: context,
      form: formState,
      setForm,
    }),
    [context, formState],
  );

  const actionDepsRef = useRef(actionDeps);
  actionDepsRef.current = actionDeps;

  const onAction = useCallback(
    (descriptor: SDUIActionDescriptor) => {
      if (!actionRegistry) return;

      const signal = abortControllerRef.current.signal;
      const deps: SDUIActionDeps = {
        ...actionDepsRef.current,
        signal,
      };

      executeAction(actionRegistry, descriptor, actionContext, deps).catch(
        (err) => {
          if (typeof __DEV__ !== 'undefined' && __DEV__) {
            console.error('[SDUI] Unhandled action error:', err);
          }
        },
      );
    },
    [actionRegistry, actionContext],
  );

  const actionHandler = actionRegistry ? onAction : undefined;

  return (
    <View style={rootStyle}>
      {header &&
        renderComponent(header, mergedContext, activeRegistry, 'header', actionHandler)}

      <View style={rootStyle}>
        {(body ?? []).map((component, index) =>
          renderComponent(
            component,
            mergedContext,
            activeRegistry,
            `${component.type}-${index}`,
            actionHandler,
          ),
        )}
      </View>

      {footer &&
        renderComponent(footer, mergedContext, activeRegistry, 'footer', actionHandler)}
    </View>
  );
}

