import React from 'react';
import { CardActivity } from '@semparar/design-system-app';
import type { SDUIComponentProps, SDUIContext } from '../models';

interface CardActivityProps extends SDUIComponentProps {
  title: string;
  description?: string;
  icon?: string;
  iconRight?: string;
  showIcon?: boolean;
  showImage?: boolean;
  image?: string;
  titleTextType?: string;
  descriptionTextType?: string;
  mt?: string;
  mb?: string;
}

export default function CardActivityAdapter({
  props,
}: {
  props: CardActivityProps;
  context: SDUIContext;
}) {
  const {
    title,
    description,
    icon,
    iconRight,
    showIcon = true,
    showImage = false,
    image,
    titleTextType = 'paragraphMD',
    descriptionTextType = 'paragraphSM',
    mt = 'nano',
    mb,
  } = props;

  return (
    <CardActivity
      mt={mt as never}
      mb={mb as never}
      title={String(title)}
      titleTextType={titleTextType as never}
      description={description ? String(description) : undefined}
      descriptionTextType={descriptionTextType as never}
      icon={icon as never}
      iconRight={iconRight ? (iconRight as never) : (null as never)}
      showIcon={showIcon}
      showImage={showImage}
      image={image ? { uri: String(image) } : undefined}
      showTagLabel={false}
      hideBorder={false}
      onPress={() => {}}
    />
  );
}

