import { View, Pressable } from 'react-native';
import { Box, Text, SeparatorHorizontal } from '@semparar/design-system-app';
import type { SDUIComponentProps, SDUIContext, SDUIActionDescriptor } from '../models';

interface TabItem {
  id: number;
  title: string;
  action?: SDUIActionDescriptor;
}

interface TabBarProps extends SDUIComponentProps {
  tabs: TabItem[];
  mt?: string;
  mb?: string;
  ml?: string;
