import React from 'react';
import { Text, Icon } from '@semparar/design-system-app';
import type {
  SDUIComponentProps,
  SDUIContext,
  SDUIRichTextChild,
  SDUIActionDescriptor,
} from '../models';

interface RichTextProps extends SDUIComponentProps {
  children: SDUIRichTextChild[];
  mt?: string;
  mb?: string;
  align?: string;
}

interface SDUILinkNodeWithAction {
  type: 'link';
  text: string;
  to: string;
  trackEvent?: string;
  action?: SDUIActionDescriptor;
}

function renderNode(
  node: SDUIRichTextChild,
  index: number,
  onAction?: (descriptor: SDUIActionDescriptor) => void,
) {
  switch (node.type) {
    case 'text': {
      const style: Record<string, string> = {};
      if (node.bold) style.fontWeight = 'bold';
      if (node.italic) style.fontStyle = 'italic';
      return (
        <Text
          key={index}
          type="bodyMD"
          color={node.color}
          style={Object.keys(style).length > 0 ? style : undefined}
        >
          {node.value}
        </Text>
      );
    }
    case 'link': {
      const linkAction = (node as SDUILinkNodeWithAction).action;
      return (
        <Text
          key={index}
          type="bodyMD"
          color="PRYMARY_BASE_02"
          underline
          onPress={() => {
            if (linkAction && onAction) onAction(linkAction);
          }}
        >
          {node.text}
        </Text>
      );
    }
    case 'icon':
      return (
        <Icon
          key={index}
          name={node.name}
          color={node.color}
          size={node.size ? String(node.size) : 'sm'}
        />
      );
    case 'br':
      return '\n';
    default:
      return null;
  }
}

export default function RichTextAdapter({
  props,
  onAction,
}: {
  props: RichTextProps;
  context: SDUIContext;
  onAction?: (descriptor: SDUIActionDescriptor) => void;
}) {
  const { children, mt, mb, align } = props;

  if (!Array.isArray(children) || children.length === 0) {
    return null;
  }

  return (
    <Text type="bodyMD" mt={mt} mb={mb} align={align}>
      {children.map((node, index) => renderNode(node, index, onAction))}
    </Text>
  );
}

