import React from 'react';
import { render, fireEvent } from '@testing-library/react-native';
import { adapters, registerAllAdapters } from './index';
import { getDefaultRegistry, getRenderer } from '../registry';
import type { SDUIContext, SDUIActionDescriptor } from '../models';

jest.mock('@semparar/design-system-app', () => {
  const mockReact = require('react');
  const RN = require('react-native');
  return {
    Text: (p: any) => {
      if (p.onPress) {
        return mockReact.createElement(RN.Pressable, { onPress: p.onPress, testID: p.testID || 'ds-text-pressable' }, mockReact.createElement(RN.Text, null, p.children));
      }
      return mockReact.createElement(RN.Text, p, p.children);
    },
    Button: (p: any) =>
      mockReact.createElement(
        RN.Pressable,
        { accessibilityState: { disabled: !!p.disabled }, testID: 'ds-button', onPress: p.onPress },
        mockReact.createElement(RN.Text, null, p.text),
      ),
    Box: (p: any) => mockReact.createElement(RN.View, p, p.children),
    InputBox: (p: any) =>
      mockReact.createElement(RN.TextInput, { placeholder: p.placeholder }),
    Alert: (p: any) => mockReact.createElement(RN.Text, null, p.label),
    Icon: (p: any) => mockReact.createElement(RN.Text, null, p.name),
    ListTextIcon: (p: any) =>
      mockReact.createElement(
        RN.View,
        null,
        ...(p.items || []).map((item: any, i: number) =>
          mockReact.createElement(RN.Text, { key: i }, item.description),
        ),
      ),
    SeparatorHorizontal: () =>
      mockReact.createElement(RN.View, { testID: 'separator' }),
    CardVehicleTags: (p: any) =>
      mockReact.createElement(
        RN.View,
        { testID: 'card-vehicle-tags' },
        mockReact.createElement(RN.Text, null, p.vehicleName),
        mockReact.createElement(RN.Text, null, p.status),
        p.onGhostButtonPress ? mockReact.createElement(RN.Pressable, { testID: 'ghost-button', onPress: p.onGhostButtonPress }) : null,
      ),
    CardPoints: (p: any) =>
      mockReact.createElement(
        RN.View,
        { testID: 'card-points' },
        mockReact.createElement(RN.Text, null, p.title),
        mockReact.createElement(RN.Text, null, p.valuePoints),
        p.onPressIconInfo ? mockReact.createElement(RN.Pressable, { testID: 'icon-info-button', onPress: p.onPressIconInfo }) : null,
      ),
    SearchUsed: (p: any) =>
      mockReact.createElement(RN.TextInput, { placeholder: p.placeholder }),
    DetailTransactionValue: (p: any) =>
      mockReact.createElement(
        RN.View,
        { testID: 'detail-transaction-value' },
        mockReact.createElement(RN.Text, null, p.title),
        mockReact.createElement(RN.Text, null, p.points),
      ),
    TagLabel: (p: any) =>
      mockReact.createElement(
        RN.View,
        { testID: 'tag-label' },
        mockReact.createElement(RN.Text, null, p.text),
      ),
    CardActivity: (p: any) =>
      mockReact.createElement(
        RN.View,
        { testID: 'card-activity' },
        mockReact.createElement(RN.Text, null, p.title),
        p.description
          ? mockReact.createElement(RN.Text, null, p.description)
          : null,
        p.onPress ? mockReact.createElement(RN.Pressable, { testID: 'card-activity-press', onPress: p.onPress }) : null,
      ),
    Header: (p: any) =>
      mockReact.createElement(
        RN.View,
        { testID: 'ds-header' },
        mockReact.createElement(RN.Text, null, p.title),
        p.iconLeft
          ? mockReact.createElement(RN.Text, null, p.iconLeft)
          : null,
        p.onBack ? mockReact.createElement(RN.Pressable, { testID: 'header-back', onPress: p.onBack }) : null,
      ),
  };
});

const emptyContext: SDUIContext = {};

describe('SDUI Adapters', () => {
  it('exports all 23 adapters', () => {
    const expected = [
      'heading',
      'text',
      'balance_display',
      'points_input',
      'button',
      'link',
      'alert',
      'list_text_icon',
      'separator',
      'icon_text_row',
      'section_heading',
      'rich_text',
      'voucher_card',
      'empty_state',
      'points_card',
      'tab_bar',
      'transaction_item',
      'date_separator',
      'detail_header',
      'tag_label',
      'key_value_row',
      'card_activity',
      'nav_header',
    ];
    expect(Object.keys(adapters)).toEqual(expected);
  });

  it('registers all adapters to the default registry', () => {
    registerAllAdapters();
    const registry = getDefaultRegistry();

    Object.keys(adapters).forEach(type => {
      expect(getRenderer(registry, type)).toBeDefined();
    });
  });

