    34→      if (node.italic) style.fontStyle = 'italic';
    35→      return (
    36→        <Text
    37→          key={index}
    38→          type="bodyMD"
    39→          color={node.color}
    40→          style={Object.keys(style).length > 0 ? style : undefined}
    41→        >
    42→          {node.value}
    43→        </Text>
    44→      );
    45→    }
    46→    case 'link': {
    47→      const linkAction = (node as SDUILinkNodeWithAction).action;
    48→      return (
    49→        <Text
    50→          key={index}
    51→          type="bodyMD"
    52→          color="PRYMARY_BASE_02"
    53→          underline
    54→          onPress={() => {
    55→            if (linkAction && onAction) onAction(linkAction);
    56→          }}
    57→        >
    58→          {node.text}
    59→        </Text>
    60→      );
    61→    }
    62→    case 'icon':
    63→      return (
    64→        <Icon
