    67→          color={node.color}
    68→          size={node.size ? String(node.size) : 'sm'}
    69→        />
    70→      );
    71→    case 'br':
    72→      return '\n';
    73→    default:
    74→      return null;
    75→  }
    76→}
    77→
    78→export default function RichTextAdapter({
    79→  props,
